@@ -26,23 +26,28 @@ pub fn create_pack() -> Pack {
 }

 fn create_safe_patterns() -> Vec<SafePattern> {
+    // `(?=\s|$)` on each subcommand stops a stack name containing the
+    // subcommand keyword (e.g. `preview-stack`, `config-backup`) from
+    // making a destructive command short-circuit as safe. Without this
+    // anchor, `pulumi destroy preview-stack` would match `pulumi-preview`
+    // via `preview` in `preview-stack` and bypass the destroy rule.
     vec![
         // preview is safe (read-only)
-        safe_pattern!("pulumi-preview", r"pulumi\b.*?\s+preview\b"),
+        safe_pattern!("pulumi-preview", r"pulumi\b.*?\s+preview(?=\s|$)"),
         // stack ls/select/init are safe
-        safe_pattern!("pulumi-stack-ls", r"pulumi\b.*?\bstack\s+ls"),
-        safe_pattern!("pulumi-stack-select", r"pulumi\b.*?\bstack\s+select"),
-        safe_pattern!("pulumi-stack-init", r"pulumi\b.*?\bstack\s+init"),
+        safe_pattern!("pulumi-stack-ls", r"pulumi\b.*?\bstack\s+ls(?=\s|$)"),
+        safe_pattern!("pulumi-stack-select", r"pulumi\b.*?\bstack\s+select(?=\s|$)"),
+        safe_pattern!("pulumi-stack-init", r"pulumi\b.*?\bstack\s+init(?=\s|$)"),
         // config is safe
-        safe_pattern!("pulumi-config", r"pulumi\b.*?\s+config\b"),
+        safe_pattern!("pulumi-config", r"pulumi\b.*?\s+config(?=\s|$)"),
         // whoami is safe
-        safe_pattern!("pulumi-whoami", r"pulumi\b.*?\s+whoami\b"),
+        safe_pattern!("pulumi-whoami", r"pulumi\b.*?\s+whoami(?=\s|$)"),
         // version is safe
-        safe_pattern!("pulumi-version", r"pulumi\b.*?\s+version\b"),
+        safe_pattern!("pulumi-version", r"pulumi\b.*?\s+version(?=\s|$)"),
         // about is safe
-        safe_pattern!("pulumi-about", r"pulumi\b.*?\s+about\b"),
+        safe_pattern!("pulumi-about", r"pulumi\b.*?\s+about(?=\s|$)"),
         // logs is safe
-        safe_pattern!("pulumi-logs", r"pulumi\b.*?\s+logs\b"),
+        safe_pattern!("pulumi-logs", r"pulumi\b.*?\s+logs(?=\s|$)"),
     ]
 }
